// === 新增：不操作 DOM，仅返回 SVG 字符串 ===

export async function renderMermaidSVG(code: string): Promise<string> {
  const id = 'chat-mermaid-' + Math.random().toString(36).slice(2, 10);
  const { svg } = await mermaid.render(id, code);
  return svg;
}

export async function renderPlantUmlSVG_pure(code: string): Promise<string> {
  const normalized = normalizePlantUmlCode(code);
  return new Promise((resolve, reject) => {
    renderPlantUmlToString(
      normalized.split(/\r\n|\r|\n/),
      (svg) => resolve(svg),
      (message) => reject(new Error(message)),
    );
  });
}

export type DiagramLanguage = 'mermaid' | 'plantuml';

export async function renderDiagramSVG(
  code: string,
  language: DiagramLanguage
): Promise<string> {
  if (language === 'plantuml') return renderPlantUmlSVG_pure(code);
  return renderMermaidSVG(code);
}

// 已有函数保持不动：renderDiagram() 仍操作主预览区容器
