## 2. `src/ui/ai-common.ts` — 核心改造

### 2.1 代码块 → 图表占位符（流式阶段不渲染）

```typescript
let __pendingDiagrams: DiagramBlockDescriptor[] = [];

export function renderChatMarkdown(text: string): string {
  __pendingDiagrams = []; // 每次调用前清空
  let result = /* 原有的标题/列表/段落/文本样式 */ '';

  // --- 代码块处理 ---
  const codeRegex = /```(\w*)\n([\s\S]*?)```/g;
  let match: RegExpExecArray | null;
  while ((match = codeRegex.exec(text)) !== null) {
    const lang = match[1] || '';
    const code = match[2];

    const isDiagramLang = /^(mermaid|plantuml)$/i.test(lang);
    if (isDiagramLang) {
      const diagramId = 'd_' + Math.random().toString(36).slice(2, 10);
      const diagramLang = lang.toLowerCase() as 'mermaid' | 'plantuml';
      __pendingDiagrams.push({ diagramId, lang: diagramLang, code: code.trim() });
      result += `
        <div class="chat-diagram-placeholder" data-diagram-id="${diagramId}" data-diagram-lang="${diagramLang}">
          <div class="opt-code-block collapsed">
            <div class="opt-code-block-header">${escapeHtml(lang)}</div>
            <pre><code>${escapeDiffHtml(code.trim())}</code></pre>
            <button class="opt-code-expand-btn">展开全部</button>
          </div>
        </div>`;
    } else {
      result += `<div class="opt-code-block collapsed">...（折叠源码，不变）</div>`;
    }
  }

  // --- 追加 AskQuestion 按钮 ---
  const actions = parseActions(text);
  if (actions.length > 0) {
    result += renderActions(actions);
  }

  return result;
}
```

### 2.2 AskQuestion 共享函数

```typescript
export interface ParsedAction {
  label: string;
  action: string;
  fullMatch: string;
}

export function parseActions(content: string): ParsedAction[] {
  const regex = /\[([^\]]+)\]\(action:([^)]+)\)/g;
  const actions: ParsedAction[] = [];
  let match: RegExpExecArray | null;
  while ((match = regex.exec(content)) !== null) {
    actions.push({
      label: match[1].trim(),
      action: match[2].trim(),
      fullMatch: match[0],
    });
  }
  return actions;
}

export function renderActions(actions: ParsedAction[]): string {
  if (actions.length === 0) return '';
  return `<div class="ai-ask-actions">
    ${actions
      .map(
        (a) =>
          `<button class="ai-ask-action-btn" data-action="${escapeHtml(a.action)}">${escapeHtml(a.label)}</button>`
      )
      .join('')}
  </div>`;
}
```

### 2.3 Finalize 后异步渲染图表

```typescript
export interface DiagramBlockDescriptor {
  diagramId: string;
  lang: 'mermaid' | 'plantuml';
  code: string;
}

export async function renderDiagramBlocksAsync(
  descriptors: DiagramBlockDescriptor[],
  container: HTMLElement,
  sessionId: string
): Promise<void> {
  const BATCH_SIZE = 5;

  for (let i = 0; i < descriptors.length; i += BATCH_SIZE) {
    const batch = descriptors.slice(i, i + BATCH_SIZE);
    await Promise.allSettled(
      batch.map(async (desc) => {
        try {
          const svg = await renderDiagramSVG(desc.code, desc.lang);
          if (getCurrentActiveSessionId() !== sessionId) return; // 竞态校验

          const placeholder = container.querySelector(`[data-diagram-id="${desc.diagramId}"]`);
          if (placeholder) {
            placeholder.innerHTML = svg;
            placeholder.classList.add('chat-diagram-rendered');
            const svgEl = placeholder.querySelector('svg');
            if (svgEl) {
              svgEl.style.maxWidth = '100%';
              svgEl.style.maxHeight = '300px';
              svgEl.style.height = 'auto';
            }
          }
        } catch (err) {
          const placeholder = container.querySelector(`[data-diagram-id="${desc.diagramId}"]`);
          if (placeholder) {
            placeholder.classList.add('chat-diagram-error');
            placeholder.insertAdjacentHTML(
              'beforeend',
              `<div class="chat-diagram-error-msg">⚠️ ${escapeHtml(cleanDiagramError(err))}</div>`
            );
          }
        }
      })
    );
  }
}

export function consumePendingDiagrams(): DiagramBlockDescriptor[] {
  const result = __pendingDiagrams;
  __pendingDiagrams = [];
  return result;
}
```

## 3. `src/ui/ask-ai.ts` — 集成调用

### 3.1 `renderSessionMessages()` 中触发异步渲染

```typescript
function renderSessionMessages(container: HTMLElement): void {
  const session = sessionService.getActiveSession();
  if (!session) return;

  container.innerHTML = session.messages
    .map((msg) => {
      const contentHtml =
        msg.role === 'ai' ? renderChatMarkdown(msg.content) : escapeHtml(msg.content);
      // ... 构建消息气泡 DOM ...
      return `<div class="ai-chat-msg">${contentHtml}</div>`;
    })
    .join('');

  // ★ 新增：历史消息中的图表异步渲染
  const descriptors = consumePendingDiagrams();
  if (descriptors.length > 0) {
    renderDiagramBlocksAsync(descriptors, container, session.id);
  }
}
```

### 3.2 `finalize()` 中触发流式结束后的渲染

```typescript
const finalize = (errorMessage?: string) => {
  // ... 现有 flush、持久化逻辑 ...

  if (!errorMessage && fullContent.trim()) {
    const descriptors = extractDiagramDescriptors(fullContent); // 正则提取 mermaid/plantuml 代码块
    if (descriptors.length > 0) {
      const session = sessionService.getActiveSession();
      if (session) {
        renderDiagramBlocksAsync(descriptors, container, session.id);
      }
    }
  }
};
```

### 3.3 Action 按钮事件委托

```typescript
container.addEventListener('click', (e) => {
  const target = e.target as HTMLElement;
  if (!target.classList.contains('ai-ask-action-btn')) return;

  const action = target.dataset.action;
  if (!action) return;

  const input = document.getElementById('ai-prompt-input') as HTMLTextAreaElement;
  if (input) {
    input.value = `action:${action}`;
    handleSendWithInput(input);
  }
});
```

