// 删除本地 parseActions 和 renderContentWithActions
import { parseActions, renderActions, renderChatMarkdown } from './ai-common';

function renderContentWithActions(content: string): string {
  const markdown = renderChatMarkdown(content);
  const actions = parseActions(content);
  return markdown + renderActions(actions);
}
